1	interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: QuoteStep[];
16	}
17	
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const COMPONENT_BASE = 25;
28	const BLOCK_SIZE = 3;
29	const BLOCK_BASE = 60;
30	
31	const FIRST_INSURANCE_RATE = 0.1;
32	const CURSE_RATE = 0.5;
33	const HIGH_ENCHANTMENT_RATE = 0.3;
34	const HIGH_ENCHANTMENT_THRESHOLD = 5;
35	const PROCESSING_FEE = 5;
36	const ROUNDING_PRECISION = 6;
37	
38	const componentGroupBase = (count: number): number =>
39	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
40	
41	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
42	
43	const withSurcharge = (base: number, rate: number): number => base + base * rate;
44	
45	const isHighlyEnchanted = (item: Item): boolean =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
47	
48	const mainItemPremium = (item: Item): number => {
49	  const base = BASE_PREMIUM[item.type];
50	  const surchargeRate =
51	    FIRST_INSURANCE_RATE +
52	    (item.cursed ? CURSE_RATE : 0) +
53	    (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
54	  return withSurcharge(base, surchargeRate);
55	};
56	
57	const mainItemTotal = (items: Item[]): number =>
58	  items
59	    .filter((item) => !isComponent(item))
60	    .reduce((sum, item) => sum + mainItemPremium(item), 0);
61	
62	const componentTotal = (items: Item[]): number => {
63	  const counts: Record<string, number> = {};
64	  for (const item of items.filter(isComponent)) {
65	    counts[item.type] = (counts[item.type] ?? 0) + 1;
66	  }
67	  const base = Object.values(counts).reduce((sum, count) => sum + componentGroupBase(count), 0);
68	  return withSurcharge(base, FIRST_INSURANCE_RATE);
69	};
70	
71	const roundUpToWhole = (amount: number): number =>
72	  Math.ceil(Number(amount.toFixed(ROUNDING_PRECISION)));
73	
74	const quotePremium = (items: Item[]): number =>
75	  roundUpToWhole(mainItemTotal(items) + componentTotal(items) + PROCESSING_FEE);
76	
77	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
78	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
79	  return { results };
80	};
